mapper.select:
SELECT * FROM settlement
WHERE deleted = 0

    AND (
        settlement_no LIKE CONCAT('%', #{keyword}, '%')
        OR patient_name LIKE CONCAT('%', #{keyword}, '%')
        OR invoice_no LIKE CONCAT('%', #{keyword}, '%')
    )


    AND pay_method = #{payMethod}


    AND status = #{status}


    AND settle_time >= #{startTime}


    AND settle_time <= #{endTime}

ORDER BY settle_time DESC
